query:
-- Índice composto principal para corretor (mais usado)
CREATE INDEX IF NOT EXISTS idx_leads_corretor_created ON leads(corretorId, createdAt DESC);

-- Índice para filtro por status
CREATE INDEX IF NOT EXISTS idx_leads_status ON leads(status);

-- Índice para filtro por projeto
CREATE INDEX IF NOT EXISTS idx_leads_project ON leads(projectId);

-- Índice para filtro por origem
CREATE INDEX IF NOT EXISTS idx_leads_origem ON leads(origem);

-- Índice composto para corretor + status (queries comuns)
CREATE INDEX IF NOT EXISTS idx_leads_corretor_status ON leads(corretorId, status);

-- Índice para busca por nome (FULLTEXT para melhor performance)
CREATE FULLTEXT INDEX IF NOT EXISTS idx_leads_nome_fulltext ON leads(nome);

-- Índice para busca por telefone
CREATE INDEX IF NOT EXISTS idx_leads_telefone ON leads(telefone);

-- Índice para busca por email
CREATE INDEX IF NOT EXISTS idx_leads_email ON leads(email);

